const body = $input.item.json.body || {};
const PORTFOLIO_URL = body.url || 'https://resume.jclee.me';
const JOB_DASHBOARD_URL = body.jobDashboardUrl || 'https://resume.jclee.me/job';
const UA = 'Mozilla/5.0 (n8n Verify; +https://n8n.jclee.me)';
const TIMEOUT = 30000;
const result = { check: 'health', passed: false, details: {} };
try {
  let healthOk = false;
  for (let i = 1; i <= 3; i++) {
    try {
      const healthData = await $helpers.httpRequest({
        method: 'GET',
        url: PORTFOLIO_URL + '/health',
        headers: { 'Accept': 'application/json', 'User-Agent': UA },
        timeout: TIMEOUT
      });
      const status = healthData.status || 'unknown';
      result.details.portfolio_status = status;
      result.details.portfolio_version = healthData.version || 'unknown';
      const deployedAt = healthData.deployed_at || null;
      if (deployedAt) {
        const ageHours = Math.floor((Date.now() - new Date(deployedAt).getTime()) / 3600000);
        result.details.deployment_age_hours = ageHours;
        result.details.deployment_fresh = ageHours < 168;
      }
      if (status === 'healthy' || status === 'degraded') {
        healthOk = true;
        result.passed = status === 'healthy';
        break;
      }
    } catch (retryErr) {
      if (i < 3) await new Promise(r => setTimeout(r, 3000));
    }
  }
  if (!healthOk) {
    result.details.portfolio_status = 'unreachable';
    result.passed = false;
  }
  try {
    const jobData = await $helpers.httpRequest({
      method: 'GET',
      url: JOB_DASHBOARD_URL + '/api/health',
      headers: { 'Accept': 'application/json', 'User-Agent': UA },
      timeout: TIMEOUT
    });
    result.details.dashboard_status = jobData.status || 'unknown';
    result.details.dashboard_version = jobData.version || 'unknown';
    result.details.dashboard_db = jobData.database || 'unknown';
    if (jobData.status !== 'ok') result.passed = false;
  } catch (e) {
    result.details.dashboard_status = 'unreachable';
    result.passed = false;
  }
  const start = Date.now();
  try {
    await $helpers.httpRequest({ method: 'GET', url: PORTFOLIO_URL + '/', headers: { 'User-Agent': UA }, timeout: TIMEOUT });
    const ms = Date.now() - start;
    result.details.response_time_ms = ms;
    result.details.response_time_ok = ms < 1000;
    if (ms >= 1000) result.passed = false;
  } catch (e) {
    result.details.response_time_ms = null;
    result.passed = false;
  }
} catch (e) {
  result.details.error = e.message;
  result.passed = false;
}
return [{ json: result }];

const body = $input.item.json.body || {};
const PORTFOLIO_URL = body.url || 'https://resume.jclee.me';
const UA = 'Mozilla/5.0 (n8n Verify; +https://n8n.jclee.me)';
const TIMEOUT = 30000;
const result = { check: 'security-headers', passed: false, details: {} };
try {
  const resp = await $helpers.httpRequest({
    method: 'GET',
    url: PORTFOLIO_URL + '/',
    headers: { 'User-Agent': UA, 'Accept': 'text/html' },
    timeout: TIMEOUT,
    returnFullResponse: true
  });
  const headers = resp.headers || {};
  const csp = headers['content-security-policy'] || '';
  if (csp) {
    if (csp.includes('sha256')) {
      result.details.csp = 'strict (sha256 hashes)';
    } else if (csp.includes('unsafe-inline')) {
      result.details.csp = 'present (unsafe-inline)';
    } else {
      result.details.csp = 'present';
    }
  } else {
    result.details.csp = 'missing';
  }
  const hsts = headers['strict-transport-security'] || '';
  if (hsts) {
    result.details.hsts = hsts.includes('preload') ? 'present (with preload)' : 'present (without preload)';
  } else {
    result.details.hsts = 'missing';
  }
  const xcto = (headers['x-content-type-options'] || '').toLowerCase();
  result.details.x_content_type_options = xcto.includes('nosniff') ? 'nosniff' : 'missing';
  const xfo = headers['x-frame-options'] || '';
  result.details.x_frame_options = xfo || 'missing';
  const missing = [];
  if (!csp) missing.push('CSP');
  if (!hsts) missing.push('HSTS');
  if (!xcto.includes('nosniff')) missing.push('X-Content-Type-Options');
  if (!xfo) missing.push('X-Frame-Options');
  result.passed = missing.length === 0;
  if (missing.length > 0) result.details.missing_headers = missing;
} catch (e) {
  result.details.error = e.message;
  result.passed = false;
}
return [{ json: result }];

const body = $input.item.json.body || {};
const PORTFOLIO_URL = body.url || 'https://resume.jclee.me';
const UA = 'Mozilla/5.0 (n8n Verify; +https://n8n.jclee.me)';
const TIMEOUT = 30000;
const result = { check: 'content-integrity', passed: false, details: {} };
try {
  const htmlResp = await $helpers.httpRequest({
    method: 'GET',
    url: PORTFOLIO_URL + '/',
    headers: { 'Accept': 'text/html', 'User-Agent': UA },
    timeout: TIMEOUT
  });
  const htmlStr = typeof htmlResp === 'string' ? htmlResp : JSON.stringify(htmlResp);
  const titleMatch = htmlStr.match(/<title>([^<]+)<\/title>/i);
  const title = titleMatch ? titleMatch[1].trim() : '';
  const titleOk = title.length > 10;
  result.details.title = titleOk ? title.substring(0, 60) : ('too short or missing: "' + title + '"');
  const ogTags = ['og:title', 'og:description', 'og:image', 'og:url'];
  let ogCount = 0;
  ogTags.forEach(function (tag) {
    if (htmlStr.includes('property="' + tag + '"')) ogCount++;
  });
  result.details.og_tags = ogCount + '/4';
  let ogImageOk = false;
  try {
    const ogResp = await $helpers.httpRequest({
      method: 'GET',
      url: PORTFOLIO_URL + '/og-image.webp',
      headers: { 'User-Agent': UA },
      timeout: TIMEOUT,
      returnFullResponse: true
    });
    ogImageOk = ogResp.statusCode === 200;
    result.details.og_image = ogImageOk ? 'accessible' : ('not accessible (http ' + ogResp.statusCode + ')');
  } catch (e) {
    result.details.og_image = 'not accessible';
    ogImageOk = false;
  }
  result.passed = titleOk && ogImageOk;
} catch (e) {
  result.details.error = e.message;
  result.passed = false;
}
return [{ json: result }];

const body = $input.item.json.body || {};
const PORTFOLIO_URL = body.url || 'https://resume.jclee.me';
const UA = 'Mozilla/5.0 (n8n Verify; +https://n8n.jclee.me)';
const TIMEOUT = 30000;
const result = { check: 'performance', passed: false, details: {} };
try {
  const metricsRaw = await $helpers.httpRequest({
    method: 'GET',
    url: PORTFOLIO_URL + '/metrics',
    headers: { 'User-Agent': UA, 'Accept': 'text/plain' },
    timeout: TIMEOUT
  });
  const metricsStr = typeof metricsRaw === 'string' ? metricsRaw : '';
  let metricCount = 0;
  if (metricsStr.includes('http_requests_total')) metricCount++;
  if (metricsStr.includes('http_response_time')) metricCount++;
  if (metricsStr.includes('vitals_received')) metricCount++;
  result.details.prometheus_metrics = metricCount + '/3 found';
  if (metricCount < 1) {
    result.details.error = 'metrics endpoint returned no known metrics';
    return [{ json: result }];
  }
  const compResp = await $helpers.httpRequest({
    method: 'GET',
    url: PORTFOLIO_URL + '/',
    headers: { 'Accept-Encoding': 'gzip, br', 'User-Agent': UA },
    timeout: TIMEOUT,
    returnFullResponse: true
  });
  const encoding = ((compResp.headers || {})['content-encoding'] || '').toLowerCase();
  if (encoding.includes('br')) {
    result.details.compression = 'brotli';
  } else if (encoding.includes('gzip')) {
    result.details.compression = 'gzip';
  } else {
    result.details.compression = 'none';
  }
  const cacheControl = (compResp.headers || {})['cache-control'] || '';
  result.details.cache_control = cacheControl || 'not set';
  result.details.cache_has_max_age = cacheControl.toLowerCase().includes('max-age');
  result.passed = metricCount >= 2;
} catch (e) {
  result.details.error = e.message;
  result.passed = false;
}
return [{ json: result }];

const body = $input.item.json.body || {};
const PORTFOLIO_URL = body.url || 'https://resume.jclee.me';
const UA = 'Mozilla/5.0 (n8n Verify; +https://n8n.jclee.me)';
const TIMEOUT = 30000;
const result = { check: 'api-endpoints', passed: false, details: {} };
try {
  const vitalsData = { lcp: 1250, fid: 50, cls: 0.05, url: '/', timestamp: Date.now() };
  let vitalsOk = false;
  try {
    const vitalsResp = await $helpers.httpRequest({
      method: 'POST',
      url: PORTFOLIO_URL + '/api/vitals',
      headers: { 'Content-Type': 'application/json', 'User-Agent': UA },
      body: vitalsData,
      timeout: TIMEOUT,
      returnFullResponse: true
    });
    result.details.vitals_endpoint = 'http ' + vitalsResp.statusCode;
    vitalsOk = vitalsResp.statusCode === 200;
    if (!vitalsOk) result.details.vitals_note = 'unexpected status ' + vitalsResp.statusCode;
  } catch (e) {
    result.details.vitals_endpoint = 'unreachable';
    result.details.vitals_error = e.message;
    return [{ json: result }];
  }
  let robotsOk = false;
  try {
    const robotsRaw = await $helpers.httpRequest({
      method: 'GET',
      url: PORTFOLIO_URL + '/robots.txt',
      headers: { 'User-Agent': UA },
      timeout: TIMEOUT
    });
    const robotsStr = typeof robotsRaw === 'string' ? robotsRaw : '';
    robotsOk = robotsStr.toLowerCase().includes('user-agent');
    result.details.robots_txt = robotsOk ? 'valid' : 'invalid or missing';
    if (!robotsOk) return [{ json: result }];
  } catch (e) {
    result.details.robots_txt = 'unreachable';
    return [{ json: result }];
  }
  let sitemapOk = false;
  try {
    const sitemapRaw = await $helpers.httpRequest({
      method: 'GET',
      url: PORTFOLIO_URL + '/sitemap.xml',
      headers: { 'User-Agent': UA },
      timeout: TIMEOUT
    });
    const sitemapStr = typeof sitemapRaw === 'string' ? sitemapRaw : '';
    sitemapOk = sitemapStr.toLowerCase().includes('<urlset');
    if (sitemapOk) {
      const urlCount = (sitemapStr.match(/<url>/g) || []).length;
      result.details.sitemap_xml = 'valid (' + urlCount + ' urls)';
    } else {
      result.details.sitemap_xml = 'invalid or missing';
    }
  } catch (e) {
    result.details.sitemap_xml = 'unreachable';
    return [{ json: result }];
  }
  result.passed = vitalsOk && robotsOk && sitemapOk;
} catch (e) {
  result.details.error = e.message;
  result.passed = false;
}
return [{ json: result }];

const items = $input.all();
const results = items.map(function (item) { return item.json; });
const total = results.length;
const passed = results.filter(function (r) { return r.passed === true; }).length;
const failed = total - passed;
const overallStatus = failed === 0 ? 'passed' : 'failed';
const webhookBody = ($('webhook-trigger').first().json.body) || {};
const portfolioUrl = webhookBody.url || 'https://resume.jclee.me';
const icon = function (r) { return r.passed ? '\u2705' : '\u274c'; };
const checkDetails = results.map(function (r) {
  return {
    name: r.check,
    passed: r.passed,
    details: typeof r.details === 'object' ? JSON.stringify(r.details) : String(r.details || '')
  };
});
const statusIcon = failed === 0 ? '\u2705' : '\u274c';
const msg = '\ud83d\udd0d \ubc30\ud3ec \uac80\uc99d \uc644\ub8cc\n' +
  statusIcon + ' \uc804\uccb4 \uc0c1\ud0dc: ' + (failed === 0 ? '\uc131\uacf5' : '\uc2e4\ud328') + '\n' +
  '\ud83d\udcca \uacb0\uacfc: ' + passed + '/' + total + ' \ud1b5\uacfc\n\n' +
  results.map(function (r) {
    return icon(r) + ' ' + r.check + ': ' + (r.passed ? '\ud1b5\uacfc' : '\uc2e4\ud328');
  }).join('\n') + '\n\n' +
  '\ud83c\udf10 URL: ' + portfolioUrl;
const notifyPayload = {
  event: 'verify',
  status: overallStatus,
  checks: {
    passed: passed,
    total: total,
    details: checkDetails
  },
  timestamp: new Date().toISOString(),
  url: portfolioUrl,
  message: msg
};
return [{ json: notifyPayload }];
